        if (audObj instanceof String s) aud = s;
        else if (audObj instanceof Collection<?> c && !c.isEmpty()) aud = Objects.toString(c.iterator().next(), null);
        if (aud == null || !props.getClientId().equals(aud)) throw new RuntimeException("Invalid audience");

