class TokenResponse {
    private final String accessToken;
    private final String idToken;
    private final String refreshToken;
    private final String tokenType;
    private final Long expiresIn;

    TokenResponse(String accessToken, String idToken, String refreshToken, String tokenType, Long expiresIn) {
        this.accessToken = accessToken;
        this.idToken = idToken;
        this.refreshToken = refreshToken;
        this.tokenType = tokenType;
        this.expiresIn = expiresIn;
    }

    public String getAccessToken() {
        return accessToken;
    }

    public String getIdToken() {
        return idToken;
    }

    public String getRefreshToken() {
        return refreshToken;
    }

    public String getTokenType() {
        return tokenType;
    }

    public Long getExpiresIn() {
        return expiresIn;
    }

    static TokenResponse from(Map<String, Object> json) {
        String accessToken = Objects.toString(json.get("access_token"), null);
        String idToken = Objects.toString(json.get("id_token"), null);
        String refreshToken = Objects.toString(json.get("refresh_token"), null);
        String tokenType = Objects.toString(json.get("token_type"), null);
        Long expiresIn = null;
        Object e = json.get("expires_in");
        if (e instanceof Number n) expiresIn = n.longValue();
        else if (e != null) {
            try { expiresIn = Long.parseLong(String.valueOf(e)); } catch (Exception ignored) {}
        }
        if (accessToken == null || idToken == null) throw new RuntimeException("Missing tokens in response");
        return new TokenResponse(accessToken, idToken, refreshToken, tokenType, expiresIn);
    }
}

@Controller
class OidcAuthController {
    private static final String SESSION_USER = "OIDC_USER";
    private static final String SESSION_TOKENS = "OIDC_TOKENS";

    private final OidcClientService oidc;

    OidcAuthController(OidcClientService oidc) {
        this.oidc = oidc;
    }

    @GetMapping("/login")
    public void login(HttpServletRequest request, HttpServletResponse response) throws Exception {
        HttpSession session = request.getSession(true);
        String redirect = oidc.buildAuthorizationRedirect(session);
        response.sendRedirect(redirect);
    }

    @GetMapping("/oidc/callback")
    public void callback(HttpServletRequest request, HttpServletResponse response) throws Exception {
        HttpSession session = request.getSession(true);

        String code = request.getParameter("code");
        String state = request.getParameter("state");
        String err = request.getParameter("error");

        if (err != null) {
            response.sendError(401, "OIDC error: " + err);
            return;
        }

        String expectedState = (String) session.getAttribute("OIDC_STATE");
        String expectedNonce = (String) session.getAttribute("OIDC_NONCE");
        session.removeAttribute("OIDC_STATE");
        session.removeAttribute("OIDC_NONCE");

        if (expectedState == null || state == null || !MessageDigest.isEqual(
                expectedState.getBytes(StandardCharsets.UTF_8),
                state.getBytes(StandardCharsets.UTF_8))) {
            response.sendError(401, "Invalid state");
            return;
        }

        TokenResponse tokens = oidc.exchangeCodeForTokens(code);
        Map<String, Object> idClaims = oidc.parseAndValidateIdToken(tokens.getIdToken(), expectedNonce);
        Map<String, Object> userInfo = oidc.fetchUserInfo(tokens.getAccessToken());
        OidcSessionUser user = oidc.createSessionUser(idClaims, userInfo);

        session.setAttribute(SESSION_USER, user);
        session.setAttribute(SESSION_TOKENS, tokens);

        response.sendRedirect("/app");
    }

    @PostMapping("/logout")
    public void logout(HttpServletRequest request, HttpServletResponse response) throws Exception {
        HttpSession session = request.getSession(false);
        if (session != null) session.invalidate();
        response.sendRedirect("/app");
    }

    @GetMapping("/app")
    public void app(HttpServletRequest request, HttpServletResponse response) throws Exception {
        HttpSession session = request.getSession(false);
        OidcSessionUser user = session == null ? null : (OidcSessionUser) session.getAttribute(SESSION_USER);

        response.setContentType("text/html; charset=utf-8");
        StringBuilder html = new StringBuilder();
        html.append("<!doctype html><html><head><title>OIDC Client</title></head><body>");
        if (user == null) {
            html.append("<h2>Not authenticated</h2>");
            html.append("<p><a href=\"/login\">Login with OIDC</a></p>");
        } else {
            html.append("<h2>Authenticated</h2>");
            html.append("<p>sub: ").append(escape(user.getSubject())).append("</p>");
            html.append("<p>name: ").append(escape(user.getName())).append("</p>");
            html.append("<p>email: ").append(escape(user.getEmail())).append("</p>");
            html.append("<form method=\"post\" action=\"/logout\"><button type=\"submit\">Logout</button></form>");
            html.append("<h3>id_token claims</h3><pre>").append(escape(pretty(user.getIdTokenClaims()))).append("</pre>");
            html.append("<h3>userinfo</h3><pre>").append(escape(pretty(user.getUserInfoClaims()))).append("</pre>");
        }
        html.append("</body></html>");
        response.getWriter().write(html.toString());
    }

    private static String pretty(Map<String, Object> m) {
        if (m == null) return "";
        StringBuilder sb = new StringBuilder();
        List<String> keys = new ArrayList<>();
        for (String k : m.keySet()) keys.add(k);
        Collections.sort(keys);
        for (String k : keys) {
            sb.append(k).append(": ").append(String.valueOf(m.get(k))).append("\n");
        }
        return sb.toString();
    }

    private static String escape(String s) {
        if (s == null) return "";
        return s.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;")
                .replace("\"", "&quot;").replace("'", "&#39;");
    }
}

